import os
import sys
from collections import defaultdict

def get_size(start_path = '.'):
    total_size = 0
    for dirpath, dirnames, filenames in os.walk(start_path):
        for f in filenames:
            fp = os.path.join(dirpath, f)
            # skip if it is symbolic link
            if not os.path.islink(fp):
                total_size += os.path.getsize(fp)
    return total_size

def print_tree(start_path, folder_details, depth=1, limit=10):
    if depth > limit:
        return
    largest_dirs = sorted(folder_details.items(), key=lambda x: x[1], reverse=True)[:limit]
    for item in largest_dirs:
        print("    " * depth + f"{item[0]} ({sizeof_fmt(item[1])})")
        new_path = os.path.join(start_path, item[0])
        if os.path.isdir(new_path):
            try:
                new_folder_details = {name: get_size(os.path.join(new_path, name)) for name in os.listdir(new_path)}
                print_tree(new_path, new_folder_details, depth + 1, limit)
            except PermissionError:
                continue

def sizeof_fmt(num, suffix='B'):
    for unit in ['','Ki','Mi','Gi','Ti','Pi','Ei','Zi']:
        if abs(num) < 1024.0:
            return "%3.1f%s%s" % (num, unit, suffix)
        num /= 1024.0
    return "%.1f%s%s" % (num, 'Yi', suffix)

def disk_usage_analyzer(path='.', limit=10):
    if not os.path.exists(path):
        print("Path does not exist.")
        return
    if not os.path.isdir(path):
        print("Path is not a directory.")
        return

    folder_details = {name: get_size(os.path.join(path, name)) for name in os.listdir(path)}
    print(f"Disk usage for: {path}")
    print_tree(path, folder_details, limit=limit)

if __name__ == "__main__":
    if len(sys.argv) > 1:
        disk_usage_analyzer(sys.argv[1])
    else:
        print("Usage: python script.py [path]")

